import React from "react";
import styles from "./cart.module.css";
import Counter from "./counter";
import { useSelector } from "react-redux";
import { RootState } from "../../../app/store";

// ... other imports ...

interface CartProps {
  imgSrc: string;
  to: string;
}

const Cart: React.FC<CartProps> = ({ imgSrc, to }) => {
  // Use useSelector to get the cart items and totalCount from the Redux store
  const { totalCount } = useSelector((state: RootState) => state.cart);

  return (
    <>
      <a className={styles.cart} href={to}>
        <img src={imgSrc} width={26} height={26} alt="icon-cart" />
      </a>
      <div className={styles.counter}>
        {totalCount > 0 && <Counter count={totalCount} />}
      </div>
    </>
  );
};

export default Cart;
